parameters.jsCode:
// Build a synthetic-but-honest audit for each application-funnel lead.
// The gap is STRUCTURAL: application funnels almost universally lack a recovery
// sequence for people who start and don't finish. We do NOT claim to have opted in;
// the gap is inferred from the funnel type, as a human strategist would assess it.
const out = [];
for (const it of $input.all()) {
  const r = it.json;
  const company = r.company_name || 'this business';
  const gap = 'Application funnel with no visible recovery sequence for people who start the '
    + 'application and do not finish. Those are the warmest, highest-intent leads (' + company
    + ' pre-qualified them by getting them to start), and they are leaking with no follow-up '
    + 'to bring them back. Typically 30-50% of application starts go unfinished; a 2-3 email '
    + 'recovery flow recovers a meaningful slice.';
  out.push({ json: { lead_id: r.lead_id, gap_summary: gap } });
}
return out;

